population.algorithm:
Iteratively evaluate insertion cost deltas across all feasible positions in all existing assigns plus a new assign candidate, selecting the minimum-cost feasible insertion for each order while preserving all previous assignments.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
    for shipIdx := range oris {
        bestDelta := math.MaxFloat64
        bestAssignIdx := -1
        var savedBestAssign Assign
        ori := oris[shipIdx]
        des := dess[shipIdx]
        shipID := total_ship + shipIdx

        numAssignsToTry := dispatch.AssignsLen + 1
        for tryIdx := 0; tryIdx < numAssignsToTry; tryIdx++ {
            originalCost := dispatch.Assigns[tryIdx].Cost

            if tryIdx == dispatch.AssignsLen {
                dispatch.Assigns[tryIdx] = Assign{}
            }

            savedState := dispatch.Assigns[tryIdx]

            added := dispatch.Assigns[tryIdx].AddShip(shipID, ori, des)
            if !added {
                continue
            }

            dispatch.Assigns[tryIdx].GenRoute()
            if dispatch.Assigns[tryIdx].Cost < 0 {
                dispatch.Assigns[tryIdx] = savedState
                dispatch.Assigns[tryIdx].GenRoute()
                continue
            }

            delta := dispatch.Assigns[tryIdx].Cost - originalCost
            if delta < bestDelta {
                bestDelta = delta
                bestAssignIdx = tryIdx
                savedBestAssign = dispatch.Assigns[bestAssignIdx]
            }

            dispatch.Assigns[tryIdx] = savedState
            dispatch.Assigns[tryIdx].GenRoute()
        }

        if bestAssignIdx >= 0 {
            dispatch.Assigns[bestAssignIdx] = savedBestAssign
            if bestAssignIdx >= dispatch.AssignsLen {
                dispatch.AssignsLen++
            }
        } else {
            newIdx := dispatch.AssignsLen
            dispatch.Assigns[newIdx] = Assign{}
            ok := dispatch.Assigns[newIdx].AddShip(shipID, ori, des)
            if ok {
                dispatch.Assigns[newIdx].GenRoute()
                if dispatch.Assigns[newIdx].Cost >= 0 {
                    dispatch.AssignsLen++
                } else {
                    dispatch.Assigns[newIdx] = Assign{}
                }
            }
        }
    }

    dispatch.RenewnTotalCost()
    return dispatch

