population.algorithm:
Greedy insertion with time-window-aware scoring prioritizing minimal delay and distance increase, using penalty-weighted cost deltas to select among feasible inserts, always falling back to least-cost existing route or new assign if full.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	const (
		timePenaltyWeight = 5.0
		distanceWeight    = 1.0
		maxWaitPenalty    = 3.0
	)
	type candidate struct {
		idx       int
		score     float64
		costDelta float64
	}
	for jj := 0; jj < len(oris); jj++ {
		var candidates []candidate
		orderId := total_ship + jj
		ori := oris[jj]
		des := dess[jj]

		for ii := 0; ii < dispatch.AssignsLen; ii++ {
			prevCost := dispatch.Assigns[ii].Cost
			ok := dispatch.Assigns[ii].AddShip(orderId, ori, des)
			if ok {
				dispatch.Assigns[ii].GenRoute()
				newCost := dispatch.Assigns[ii].Cost
				delta := newCost - prevCost
				waitFactor := 0.0
				if ori.TimeStart > 0 {
					waitEst := 0.0
					stCur := dispatch.Assigns[ii].StationCurrent
					distOri := cal_dis(stCur, ori)
					arrTime := distOri
					if arrTime < float64(ori.TimeStart) {
						waitEst = float64(ori.TimeStart) - arrTime
					}
					waitFactor = waitEst * maxWaitPenalty
				}
				timeWinRisk := 0.0
				if ori.TimeEnd > 0 {
					winLen := float64(ori.TimeEnd - ori.TimeStart)
					if winLen <= 0 {
						winLen = 1.0
					}
					risk := 1.0 / winLen
					timeWinRisk = risk * timePenaltyWeight
				}
				score := distanceWeight*delta + timePenaltyWeight*timeWinRisk + waitFactor
				candidates = append(candidates, candidate{idx: ii, score: score, costDelta: delta})
				dispatch.Assigns[ii].RemoveShip(orderId)
				dispatch.Assigns[ii].GenRoute()
			}
		}

		bestCandidate := candidate{idx: -1, score: 1e100}
		for _, c := range candidates {
			if c.score < bestCandidate.score {
				bestCandidate = c
			}
		}

		if bestCandidate.idx != -1 {
			dispatch.Assigns[bestCandidate.idx].AddShip(orderId, ori, des)
			dispatch.Assigns[bestCandidate.idx].GenRoute()
		} else {
			fallbackInserted := false
			for ii := 0; ii < dispatch.AssignsLen; ii++ {
				prevCost := dispatch.Assigns[ii].Cost
				ok := dispatch.Assigns[ii].AddShip(orderId, ori, des)
				if ok {
					dispatch.Assigns[ii].GenRoute()
					newCost := dispatch.Assigns[ii].Cost
					delta := newCost - prevCost
					if !fallbackInserted || delta < bestCandidate.costDelta {
						bestCandidate.idx = ii
						bestCandidate.costDelta = delta
						fallbackInserted = true
					}
					dispatch.Assigns[ii].RemoveShip(orderId)
					dispatch.Assigns[ii].GenRoute()
				}
			}
			if fallbackInserted && bestCandidate.idx != -1 {
				dispatch.Assigns[bestCandidate.idx].AddShip(orderId, ori, des)
				dispatch.Assigns[bestCandidate.idx].GenRoute()
			} else if dispatch.AssignsLen < MAXASSIGNS {
				dispatch.Assigns[dispatch.AssignsLen].AddShip(orderId, ori, des)
				dispatch.Assigns[dispatch.AssignsLen].GenRoute()
				dispatch.AssignsLen++
			} else {
				targetIdx := 0
				minPrevCost := dispatch.Assigns[0].Cost
				for ii := 1; ii < MAXASSIGNS; ii++ {
					if dispatch.Assigns[ii].Cost < minPrevCost {
						minPrevCost = dispatch.Assigns[ii].Cost
						targetIdx = ii
					}
				}
				dispatch.Assigns[targetIdx].AddShip(orderId, ori, des)
				dispatch.Assigns[targetIdx].GenRoute()
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

