population.algorithm:
Modified greedy insertion with regret-based neighbor evaluation and ordered candidate list to improve assignment quality while maintaining feasibility.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type trialResult struct {
		assignIdx   int
		costDelta   float64
		oldCost     float64
		insertOk    bool
		stationSave interface{}
	}
	const MAXTRIES = MAXASSIGNS
	orders := len(oris)
	if orders == 0 {
		dispatch.RenewnTotalCost()
		return dispatch
	}
	nextNewAssign := dispatch.AssignsLen
	for oi := 0; oi < orders; oi++ {
		bestTrials := make([]trialResult, 0, MAXASSIGNS)
		ori, des := oris[oi], dess[oi]
		shipID := total_ship + oi
		for ai := 0; ai < nextNewAssign+1 && ai < MAXASSIGNS; ai++ {
			if ai == nextNewAssign {
				if ai >= MAXASSIGNS {
					continue
				}
			}
			assign := &dispatch.Assigns[ai]
			oldCost := assign.Cost
			added := assign.AddShip(shipID, ori, des)
			if !added {
				bestTrials = append(bestTrials, trialResult{assignIdx: ai, costDelta: 1e100, oldCost: oldCost, insertOk: false})
				continue
			}
			assign.GenRoute()
			newCost := assign.Cost
			costDelta := newCost - oldCost
			if newCost < 0 {
				assign.RemoveShip(shipID)
				assign.GenRoute()
				bestTrials = append(bestTrials, trialResult{assignIdx: ai, costDelta: 1e100, oldCost: oldCost, insertOk: false})
			} else {
				bestTrials = append(bestTrials, trialResult{assignIdx: ai, costDelta: costDelta, oldCost: oldCost, insertOk: true})
				assign.RemoveShip(shipID)
				assign.GenRoute()
			}
		}
		chosenIdx := -1
		minDelta := 1e100
		secondMin := 1e100
		var feasible []trialResult
		for _, tr := range bestTrials {
			if tr.insertOk {
				feasible = append(feasible, tr)
				if tr.costDelta < minDelta {
					secondMin = minDelta
					minDelta = tr.costDelta
					chosenIdx = tr.assignIdx
				} else if tr.costDelta < secondMin {
					secondMin = tr.costDelta
				}
			}
		}
		regret := secondMin - minDelta
		finalIdx := chosenIdx
		if regret <= 0 && len(feasible) > 1 {
			sort.SliceStable(feasible, func(i, j int) bool {
				di := feasible[i].costDelta
				dj := feasible[j].costDelta
				return di < dj || (di == dj && feasible[i].assignIdx < feasible[j].assignIdx)
			})
			finalIdx = feasible[0].assignIdx
		}
		if finalIdx == -1 {
			for ai := 0; ai < nextNewAssign+1 && ai < MAXASSIGNS; ai++ {
				if ai == nextNewAssign && ai < MAXASSIGNS {
					finalIdx = ai
					break
				}
			}
		}
		target := &dispatch.Assigns[finalIdx]
		ok := target.AddShip(shipID, ori, des)
		if !ok && finalIdx >= nextNewAssign && finalIdx < MAXASSIGNS {
			ok = target.AddShip(shipID, ori, des)
		}
		if ok {
			target.GenRoute()
			if finalIdx >= nextNewAssign {
				nextNewAssign++
			}
		} else {
			if finalIdx < MAXASSIGNS {
				fallbackOK := target.AddShip(shipID, ori, des)
				if fallbackOK {
					target.GenRoute()
					if finalIdx >= nextNewAssign {
						nextNewAssign++
					}
				} else {
					for fi := 0; fi < MAXASSIGNS; fi++ {
						if fi != finalIdx {
							fbAssign := &dispatch.Assigns[fi]
							if fbAssign.AddShip(shipID, ori, des) {
								fbAssign.GenRoute()
								if fi >= nextNewAssign {
									nextNewAssign = fi + 1
								}
								break
							}
						}
					}
				}
			}
		}
	}
	if nextNewAssign > dispatch.AssignsLen {
		dispatch.AssignsLen = nextNewAssign
	}
	dispatch.RenewnTotalCost()
	return dispatch

