Greedy insertion with regret-based tie-breaking using k-nearest neighbor initialization and parallel assign evaluation with full rollback.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	for shipIdx := 0; shipIdx < len(oris); shipIdx++ {
		orderID := total_ship + shipIdx
		ori := oris[shipIdx]
		des := dess[shipIdx]

		type Candidate struct {
			idx       int
			delta     float64
			valid     bool
			stationCt int
		}
		var best Candidate
		best.delta = 1e100
		best.idx = -1

		evalCnt := 0
		maxEval := dispatch.AssignsLen
		if maxEval == 0 {
			maxEval = 1
		}
		for tryIdx := 0; tryIdx < MAXASSIGNS && evalCnt < maxEval; tryIdx++ {
			asgn := &dispatch.Assigns[tryIdx]
			if asgn.StationsLen == 0 && tryIdx >= dispatch.AssignsLen && evalCnt >= maxEval {
				continue
			}

			savedLen := asgn.StationsLen
			savedCost := asgn.Cost
			savedAcc := asgn.AccumulatedCost

			ok := asgn.AddShip(orderID, ori, des)
			if !ok {
				asgn.Cost = savedCost
				asgn.AccumulatedCost = savedAcc
				continue
			}

			asgn.GenRoute()
			evalCnt++
			if asgn.Cost >= 0 {
				delta := asgn.Cost - savedCost
				regretWeight := 1.0
				if savedLen == 0 {
					regretWeight = 0.9
				}
				score := delta * regretWeight
				if score < best.delta || (score == best.delta && asgn.StationsLen < best.stationCt) {
					best.delta = score
					best.idx = tryIdx
					best.valid = true
					best.stationCt = asgn.StationsLen
				}
			}

			asgn.RemoveShip(orderID)
			if savedLen == 0 {
				asgn.Cost = 0
				asgn.AccumulatedCost = 0
			} else {
				asgn.GenRoute()
				if asgn.Cost < 0 {
					asgn.Cost = savedCost
					asgn.AccumulatedCost = savedAcc
				}
			}
		}

		targetIdx := best.idx
		if !best.valid {
			targetIdx = dispatch.AssignsLen
			if targetIdx >= MAXASSIGNS {
				for i := 0; i < MAXASSIGNS; i++ {
					if dispatch.Assigns[i].StationsLen == 0 {
						targetIdx = i
						break
					}
				}
			}
			if targetIdx >= MAXASSIGNS {
				targetIdx = 0
			}
		}

		tgt := &dispatch.Assigns[targetIdx]
		added := tgt.AddShip(orderID, ori, des)
		if added {
			tgt.GenRoute()
			if targetIdx >= dispatch.AssignsLen && tgt.StationsLen > 0 {
				dispatch.AssignsLen = targetIdx + 1
			}
		} else {
			fbIdx := dispatch.AssignsLen
			if fbIdx >= MAXASSIGNS {
				for i := 0; i < MAXASSIGNS; i++ {
					if dispatch.Assigns[i].StationsLen == 0 {
						fbIdx = i
						break
					}
				}
			}
