		type Candidate struct {
			idx       int
			delta     float64
			valid     bool
			stationCt int
		}
		var best Candidate
		best.delta = 1e100
		best.idx = -1

		evalCnt := 0
		maxEval := dispatch.AssignsLen
		if maxEval == 0 {
			maxEval = 1
		}
		for tryIdx := 0; tryIdx < MAXASSIGNS && evalCnt < maxEval; tryIdx++ {
			asgn := &dispatch.Assigns[tryIdx]
			if asgn.StationsLen == 0 && tryIdx >= dispatch.AssignsLen && evalCnt >= maxEval {
				continue
			}

			savedLen := asgn.StationsLen
			savedCost := asgn.Cost
			savedAcc := asgn.AccumulatedCost

			ok := asgn.AddShip(orderID, ori, des)
			if !ok {
				asgn.Cost = savedCost
				asgn.AccumulatedCost = savedAcc
				continue
			}

			asgn.GenRoute()
			evalCnt++
			if asgn.Cost >= 0 {
				delta := asgn.Cost - savedCost
				regretWeight := 1.0
				if savedLen == 0 {
