For each order, evaluate all feasible insertion positions across all assigns using cost deltas, select the minimum-cost feasible insertion, and use a new assign as fallback.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	orderCount := len(oris)
	assignIndices := make([]int, 0, dispatch.AssignsLen)
	for i := 0; i < dispatch.AssignsLen; i++ {
		assignIndices = append(assignIndices, i)
	}

	newAssignStartIdx := dispatch.AssignsLen
	fallbackIdx := -1

	for orderIdx := 0; orderIdx < orderCount; orderIdx++ {
		shipID := total_ship + orderIdx
		bestAssignIdx := -1
		bestDelta := math.MaxFloat64
		ori := oris[orderIdx]
		des := dess[orderIdx]

		for _, assignIdx := range assignIndices {
			currAssign := &dispatch.Assigns[assignIdx]
			originalCost := currAssign.Cost

			success := currAssign.AddShip(shipID, ori, des)
			if success {
				currAssign.GenRoute()
				newCost := currAssign.Cost
				delta := newCost - originalCost
				currAssign.RemoveShip(shipID)
				currAssign.GenRoute()

				if delta < bestDelta && newCost >= 0 {
					bestDelta = delta
					bestAssignIdx = assignIdx
				}
			}
		}

		if bestAssignIdx == -1 {
			if fallbackIdx == -1 || fallbackIdx >= newAssignStartIdx {
				fallbackIdx = dispatch.AssignsLen
				if dispatch.AssignsLen >= MAXASSIGNS {
					continue
				}
				tempAssign := &dispatch.Assigns[fallbackIdx]
				if tempAssign.AddShip(shipID, ori, des) {
					tempAssign.GenRoute()
					if tempAssign.Cost >= 0 {
						dispatch.AssignsLen++
						assignIndices = append(assignIndices, fallbackIdx)
					} else {
						tempAssign.RemoveShip(shipID)
						tempAssign.GenRoute()
					}
				}
			} else {
				fallbackAssign := &dispatch.Assigns[fallbackIdx]
				if fallbackAssign.AddShip(shipID, ori, des) {
					fallbackAssign.GenRoute()
					if fallbackAssign.Cost < 0 {
						fallbackAssign.RemoveShip(shipID)
						fallbackAssign.GenRoute()
						fallbackIdx = -1
					}
				}
			}
		} else {
			chosenAssign := &dispatch.Assigns[bestAssignIdx]
			chosenAssign.AddShip(shipID, ori, des)
			chosenAssign.GenRoute()
		}
	}

	dispatch.RenewnTotalCost()
	return dispatch

