Regret-based greedy insertion with weighted penalty minimization: compute insertion regret across top-k best positions and choose based on combined cost increase and opportunity loss, falling back to first feasible assign if none optimal.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	for orderIdx := 0; orderIdx < len(oris); orderIdx++ {
		shipID := total_ship + orderIdx
		type candidate struct {
			idx       int
			delta     float64
			feasible  bool
		}
		var candidates []candidate

		for ai := 0; ai < dispatch.AssignsLen; ai++ {
			assign := &dispatch.Assigns[ai]
			oldCost := assign.Cost
			ok := assign.AddShip(shipID, oris[orderIdx], dess[orderIdx])
			if !ok {
				continue
			}
			assign.GenRoute()
			newCost := assign.Cost
			var delta float64 = -1.0
			if oldCost >= 0 && newCost >= 0 {
				delta = newCost - oldCost
			}
			candidates = append(candidates, candidate{idx: ai, delta: delta, feasible: true})
			assign.RemoveShip(shipID)
			assign.GenRoute()
		}

		bestIdx := -1
		if len(candidates) > 0 {
			const k = 3
			type scored struct {
				idx   int
				score float64
			}
			var scoredList []scored
			for _, c := range candidates {
				if c.delta < 0 {
					continue
				}
				regret := 0.0
				if len(candidates) > 1 {
					minOther := c.delta
					count := 0
					for _, oc := range candidates {
						if oc.idx == c.idx || oc.delta < 0 {
							continue
						}
						if count == 0 || oc.delta < minOther {
							minOther = oc.delta
						}
						count++
					}
					if count > 0 {
						regret = c.delta - minOther
					}
				}
				alpha := 0.7
				score := alpha*c.delta + (1-alpha)*regret
				scoredList = append(scoredList, scored{idx: c.idx, score: score})
			}
			if len(scoredList) > 0 {
				bestScore := scoredList[0].score
				bestIdx = scoredList[0].idx
				for i := 1; i < len(scoredList); i++ {
					if scoredList[i].score < bestScore {
						bestScore = scoredList[i].score
						bestIdx = scoredList[i].idx
					}
				}
			}
			if bestIdx == -1 && len(candidates) > 0 {
				bestIdx = candidates[0].idx
				bestDelta := candidates[0].delta
				for i := 1; i < len(candidates); i++ {
					if candidates[i].delta >= 0 && (bestDelta < 0 || candidates[i].delta < bestDelta) {
						bestDelta = candidates[i].delta
						bestIdx = candidates[i].idx
					}
				}
			}
		}

		if bestIdx != -1 {
			target := &dispatch.Assigns[bestIdx]
			target.AddShip(shipID, oris[orderIdx], dess[orderIdx])
			target.GenRoute()
		} else {
			if dispatch.AssignsLen < MAXASSIGNS {
				newAssign := &dispatch.Assigns[dispatch.AssignsLen]
				ok := newAssign.AddShip(shipID, oris[orderIdx], dess[orderIdx])
				if ok {
					newAssign.GenRoute()
					dispatch.AssignsLen++
				}
			} else {
				for ai := 0; ai < dispatch.AssignsLen; ai++ {
					assign := &dispatch.Assigns[ai]
					if assign.AddShip(shipID, oris[orderIdx], dess[orderIdx]) {
						assign.GenRoute()
						break
					}
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

