Greedy insertion with time-window feasibility and minimal marginal cost increase per order using best-fit selection across existing and new assigns.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type TrialResult struct {
		assignIdx int
		costDelta float64
		success   bool
	}
	for shipIDOffset := 0; shipIDOffset < len(oris); shipIDOffset++ {
		bestTrial := TrialResult{assignIdx: -1, costDelta: 1e18, success: false}
		orderOri := oris[shipIDOffset]
		orderDes := dess[shipIDOffset]
		realShipID := total_ship + shipIDOffset
		numExisting := dispatch.AssignsLen
		for tryAssignIdx := 0; tryAssignIdx <= numExisting; tryAssignIdx++ {
			if tryAssignIdx == MAXASSIGNS {
				continue
			}
			curAssign := &dispatch.Assigns[tryAssignIdx]
			oldCost := curAssign.Cost
			addOk := curAssign.AddShip(realShipID, orderOri, orderDes)
			if !addOk {
				continue
			}
			curAssign.GenRoute()
			newCost := curAssign.Cost
			if newCost < 0 || oldCost < 0 {
				curAssign.RemoveShip(realShipID)
				curAssign.GenRoute()
				continue
			}
			delta := newCost - oldCost
			if delta < bestTrial.costDelta {
				bestTrial.assignIdx = tryAssignIdx
				bestTrial.costDelta = delta
				bestTrial.success = true
			}
			curAssign.RemoveShip(realShipID)
			curAssign.GenRoute()
		}
		targetAssignIdx := bestTrial.assignIdx
		if targetAssignIdx < 0 {
			targetAssignIdx = dispatch.AssignsLen
			if targetAssignIdx >= MAXASSIGNS {
				targetAssignIdx = 0
			}
		}
		finalAssign := &dispatch.Assigns[targetAssignIdx]
		addOk := finalAssign.AddShip(realShipID, orderOri, orderDes)
		if !addOk {
			finalAssign.AddShip(realShipID, orderOri, orderDes)
		}
		finalAssign.GenRoute()
		if targetAssignIdx >= dispatch.AssignsLen && targetAssignIdx < MAXASSIGNS {
			dispatch.AssignsLen++
		}
	}
	dispatch.RenewnTotalCost()
