		dispatch.RenewnTotalCost()
		return dispatch
	}
	for jj := 0; jj < orderCount; jj++ {
		bestCand := candidate{-1, INF_COST, false}
		shipID := total_ship + jj
		ori := oris[jj]
		des := dess[jj]
		maxExisting := dispatch.AssignsLen
		totalChecks := maxExisting
		if maxExisting < MAXASSIGNS {
			totalChecks++
		}
		for tryIdx := 0; tryIdx < totalChecks; tryIdx++ {
			isNewSlot := (tryIdx >= maxExisting)
			var assignIdx int
			if isNewSlot {
				assignIdx = maxExisting
			} else {
				assignIdx = tryIdx
			}
			currentAssign := &dispatch.Assigns[assignIdx]
			savedStateExists := currentAssign.StationsLen > 0
