			if added {
				dispatch.Assigns[ii].GenRoute()
				newCost := dispatch.Assigns[ii].Cost
				if newCost >= 0 {
					delta := newCost - saved
					candidates = append(candidates, cand{ii, delta, saved, true})
				}
				dispatch.Assigns[ii].RemoveShip(total_ship + jj)
				if stationCount == 0 && ii < dispatch.AssignsLen {
					dispatch.Assigns[ii].GenRoute()
				} else {
					dispatch.Assigns[ii].Cost = saved
				}
			}
		}
		if len(candidates) > 0 {
			minDelta := candidates[0].delta
			bestIdx := candidates[0].assignIdx
			for i := 1; i < len(candidates); i++ {
				if candidates[i].delta < minDelta {
					minDelta = candidates[i].delta
