func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type candidate struct {
		assignIdx int
		costDelta float64
		ok        bool
	}
	for shipIDOffset, ori := range oris {
		best := candidate{-1, 1e18, false}
		des := dess[shipIDOffset]
		orderID := total_ship + shipIDOffset
		for i := 0; i < MAXASSIGNS; i++ {
			if i >= dispatch.AssignsLen {
				break
			}
			oldCost := dispatch.Assigns[i].Cost
			savedState := dispatch.Assigns[i].StationCurrent
			ok := dispatch.Assigns[i].AddShip(orderID, ori, des)
			if ok {
				dispatch.Assigns[i].GenRoute()
				newCost := dispatch.Assigns[i].Cost
				if newCost >= 0 {
					delta := newCost - oldCost
					if delta < best.costDelta {
						best.assignIdx = i
						best.costDelta = delta
						best.ok = true
					}
				}
				dispatch.Assigns[i].RemoveShip(orderID)
				dispatch.Assigns[i].StationCurrent = savedState
				dispatch.Assigns[i].GenRoute()
			}
		}
		if best.ok {
			insertIdx := best.assignIdx
			dispatch.Assigns[insertIdx].AddShip(orderID, ori, des)
			dispatch.Assigns[insertIdx].GenRoute()
		} else {
			fallbackIdx := dispatch.AssignsLen
			if fallbackIdx < MAXASSIGNS {
				dispatch.Assigns[fallbackIdx].AddShip(orderID, ori, des)
				dispatch.Assigns[fallbackIdx].GenRoute()
				dispatch.AssignsLen++
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch
}
